import { useEffect, useRef, useState } from "react";
import html2pdf from "html2pdf.js";
import { FaDownload } from "react-icons/fa";
import { useParams } from "react-router-dom";
import { dmtDtails } from "../../../../api/login/Login";
import Loader from "../../../../common/loader/Loader";
import { imageLogo } from "../../../../asesets";
import "../../../../pages/admin/userlist/AepsInvoice.css";

function DtmReportDetails() {
  const [loading, setLoading] = useState(false);
  const param = useParams();
  const [data, setData] = useState(null);

  const invoiceRef = useRef(null);

  const downloadPDF = () => {
    const element = invoiceRef.current;

    const opt = {
      margin: [10, 10, 10, 10],
      filename: "dmt_invoice.pdf",
      image: { type: "jpeg", quality: 0.98 },
      html2canvas: { scale: 4, useCORS: true },
      jsPDF: { unit: "mm", format: "a4", orientation: "portrait" },
      pagebreak: { mode: ["avoid-all", "css", "legacy"] },
    };

    html2pdf().set(opt).from(element).save();
  };

  const dataDetails = async () => {
    setLoading(true);
    try {
      const res = await dmtDtails(param.id);
      setData(res?.data?.data);
    } catch (error) {
      console.error("Error fetching DMT details:", error);
    }
    setLoading(false);
  };

  useEffect(() => {
    dataDetails();
  }, []);

  const invoice = data?.invoice?.[0];

  return (
    <>
      {loading && <Loader />}

      <div className="aeps-invoice-container">
        <div
          id="dmt-invoice"
          className="aeps-invoice"
          ref={invoiceRef}
        >
          {/* Header */}
          <div className="invoice-header">
            <img
              src={imageLogo}
              alt="Company Logo"
              className="company-logo"
            />
          </div>

          <h1 className="invoice-h1">DMT Transaction Receipt</h1>

          {/* Details */}
          <div className="invoice-details">
            {/* Left */}
            <div className="detail-column">
              <div className="detail-item">
                <span className="label">CSP Name</span>
                <span className="value">{invoice?.shop_name}</span>
              </div>

              <div className="detail-item">
                <span className="label">Mobile Number</span>
                <span className="value">{invoice?.mobile_number}</span>
              </div>

              <div className="detail-item">
                <span className="label">Sender Name</span>
                <span className="value">{invoice?.customer_name}</span>
              </div>

              <div className="detail-item">
                <span className="label">Sender No</span>
                <span className="value">{invoice?.customer_mobile}</span>
              </div>
            </div>

            {/* Right */}
            <div className="detail-column">
              <div className="detail-item">
                <span className="label">Beneficiary</span>
                <span className="value">{invoice?.beneficiary_name}</span>
              </div>

              <div className="detail-item">
                <span className="label">Bank Name</span>
                <span className="value">{invoice?.bank_name}</span>
              </div>

              <div className="detail-item">
                <span className="label">Account No</span>
                <span className="value">{invoice?.account_number}</span>
              </div>

              <div className="detail-item">
                <span className="label">Date</span>
                <span className="value">
                  {invoice?.createdAt?.split(" ")[0]}
                </span>
              </div>
            </div>
          </div>

          {/* Table */}
          <table className="table table-striped table-bordered mt-4">
            <thead>
              <tr>
                <th>TID</th>
                <th>Status</th>
                <th>UTR</th>
                <th>Amount</th>
              </tr>
            </thead>

            <tbody>
              {invoice?.allTrans?.map((item) => (
                <tr key={item?._id}>
                  <td>{item?.tid}</td>
                  <td>{item?.status}</td>
                  <td>{item?.utr}</td>
                  <td>₹{item?.amount}</td>
                </tr>
              ))}

              <tr>
                <td colSpan="3"><b>Total</b></td>
                <td><b>₹{invoice?.totalAmount}</b></td>
              </tr>
            </tbody>
          </table>

          {/* Footer */}
          <div className="invoice-footer">
            <p>© {new Date().getFullYear()} All Rights Reserved</p>
          </div>
        </div>

        {/* Download Button */}
        <button onClick={downloadPDF} className="download-btn">
          <FaDownload /> Download PDF
        </button>
      </div>
    </>
  );
}

export default DtmReportDetails;